import * as sylkrtc from 'react-native-sylkrtc';

// Bump this any time we change the JS or native E2EE wire format.
// Both phones MUST log the same value, otherwise asymmetric video is
// almost certainly version skew rather than a codec issue.
//
// Must match SYLK_E2EE_BUILD in:
//   node_modules/react-native-webrtc/android/src/main/cpp/MediaEncryptorJni.cpp
//   node_modules/react-native-webrtc/android/src/main/cpp/sylk_e2ee.cpp
//   node_modules/react-native-webrtc/ios/RCTWebRTC/SylkZRTPBridge.mm
// (those are tracked via patches/react-native-webrtc+124.0.7.patch).
//
// At app boot we call WebRTCModule.getSylkE2EEBuild() to ask native what
// build it loaded; if it doesn't match this constant we log a loud
// warning so a stale .cxx cache or a missed patch-package run is
// caught immediately rather than weeks later via "weird E2EE bugs".
const SYLK_E2EE_BUILD = 'build-2026-05-02-public-aesgcm';

// ---------- Video quality profile -------------------------------------------
// Per-field opt-in: any field set to null is skipped, leaving WebRTC / the
// camera default in place. Default profile below is fully neutral so we
// ship with stock behavior. Override individual fields when you need to
// tune for cellular / weak networks.
//
//   width/height/frameRate -> getUserMedia constraints (camera capture)
//   maxBitrateKbps         -> RTCRtpSender.setParameters on the video sender
//
// Reference points if you want to tune:
//   480p / 24fps / 800  kbps  -> default. Reasonable mobile uplink,
//                                survives moderate packet loss on 4G/5G.
//   480p / 24fps / 1200 kbps  -> reasonable WiFi
//   240p / 15fps / 250  kbps  -> congested networks / weak hardware
//
// We ship with 480p / 24fps / 800kbps on by default. Without these the
// camera was happily handing libwebrtc 1088x1088 @ 45fps on some
// devices (phones picking their "square selfie" mode when given only
// an `ideal:` hint), which produced the high-bitrate / high-loss
// playback artefacts on the receiving side. The constraints in
// getLocalMedia are emitted with BOTH `ideal:` and `max:` so the
// camera driver is actually forced to honour them.
//
// Three named profiles — the user picks one in Preferences → Video.
// They roughly cover the standard tiers in the consumer video-call
// world:
//   '480p'   Standard.   Reasonable mobile uplink, survives moderate
//                        packet loss on 4G/5G. Default.
//   '720p'   Balanced.   Solid WiFi / strong cellular.
//   '1080p'  High.       Robust uplink (home/office WiFi, wired).
// The selection is persisted through the same accounts.settings JSON
// blob every other Preferences knob uses (setAccountSetting →
// _persistAccountSettings → SQL accounts.settings column), stored
// under accountSetting.device.videoProfile alongside cameraDevice /
// micDevice / proximityEnabled. Persists per-account, but the
// device.* namespace already exists for "this phone's hardware
// preferences" so the placement is consistent with the existing
// pattern.
export const VIDEO_PROFILES = {
    '480p':  { width:  640, height:  480, frameRate: 24, maxBitrateKbps:  800 },
    '720p':  { width: 1280, height:  720, frameRate: 30, maxBitrateKbps: 1500 },
    '1080p': { width: 1920, height: 1080, frameRate: 30, maxBitrateKbps: 3000 },
};
export const VIDEO_PROFILE_IDS = Object.keys(VIDEO_PROFILES);
export const VIDEO_PROFILE_DEFAULT_ID = '480p';

// `VIDEO_PROFILE` is kept as the live, mutable view of the active
// profile so code that already reads from it (e.g. the boot-time
// banner log a few lines below) keeps working without a rewrite.
// The shape is the same as before. _applyVideoProfileId() (method on
// App, defined further down) mutates these fields in place when the
// user picks a different profile in Preferences and immediately
// pushes the new values into setVideoEncoderTarget /
// setVideoMaxBitrateKbps so future getLocalMedia calls and any
// reapplyVideoEncoderParams pulls see the new profile.
export const VIDEO_PROFILE = { ...VIDEO_PROFILES[VIDEO_PROFILE_DEFAULT_ID] };

// Preferred video codec — applies to both outgoing offers and incoming
// answers. Both endpoints need to agree.
// Recognized values: 'VP9' | 'VP8' | 'H264'.
//
//   VP9   — primary. Best compression, broad hw decode in 2026. Verified
//           cross-platform with E2EE (Android↔iOS).
//   VP8   — fallback. Universal hw support. Verified cross-platform with E2EE.
//   H264  — supported but disables E2EE (STAP-A multi-NAL packetization
//           isn't compatible with our fixed-prefix FrameEncryptor). The
//           UI tags this codec "(no E2EE)" and the ZRTP simulation
//           refuses to install when H.264 is the negotiated codec.
//   AV1   — removed from the picker for 2026 builds. Hardware encode is
//           still rare enough on Apple/Android that production calls
//           would silently fall back to software AV1, hammering CPU and
//           thermal-throttling. Reintroduce when hw-encode is universal.
//
// At boot we set 'VP9' as a sensible default. Once the account is loaded
// from SQL, we read the per-account preference from accounts.settings
// (state.accountSetting.rtp.preferredVideoCodec) and override.
const PREFERRED_VIDEO_CODEC = 'VP9';

// ---------- preferred audio codec ------------------------------------------
// Same idea as PREFERRED_VIDEO_CODEC but for the audio m-line. libwebrtc's
// own default is 'opus' (48 kHz, FEC, stereo capable) which is what we want
// for any general-purpose call. The user-facing preference exists so that
// people whose calls land on a PSTN trunk via Asterisk can force PCMU /
// PCMA and skip the trunk-side transcoder, which often introduces audible
// jitter on long-haul links.
//
// Recognized values match what libwebrtc puts in `a=rtpmap` (case-
// insensitive on lookup):
//   opus  — 48 kHz, FEC, default. Best quality, native to WebRTC.
//   G722  — 16 kHz wideband. Useful for SIP peers that don't support opus.
//   PCMU  — 8 kHz μ-law (G.711U). PSTN-native; recommended for Asterisk
//           + PSTN destinations.
//   PCMA  — 8 kHz A-law (G.711A). Same as PCMU but the European variant.
const PREFERRED_AUDIO_CODEC = 'opus';

// ---------- per-account settings (SQL: accounts.settings) -------------------
// PER-ACCOUNT settings — stored in the SQL `accounts` table under the
// `settings` column as a single JSON blob, keyed by account URI. Loaded
// on login by _applyAccountSettings(accountId), mirrored in
// state.accountSetting, and written via setAccountSetting(key, value).
//
// Schema-wise this replaces the previous TWO stores:
//   * AsyncStorage 'devicePreferences' (per-device knobs: codec, dtmf,
//     encryption mode, audio-recording toggle, location knobs)
//   * AsyncStorage 'accountLocalProperties.<accountId>' (reserved for
//     per-account local-only properties — was effectively empty)
//
// Both are now collapsed into accounts.settings. Nothing is migrated
// from AsyncStorage: after upgrade the column is NULL for every
// existing row and parses to {} so ACCOUNT_SETTINGS_DEFAULTS takes
// effect again.
//
// The helpers below are pure data — they don't touch SQL on their own.
// Persistence is the App class's job (see _applyAccountSettings /
// setAccountSetting / _persistAccountSettings) since the DB handle and
// the active accountId both live there.

// Sectioned defaults. Each section groups settings that belong to a
// single subsystem so the dump and the Preferences modal read the
// same way:
//   rtp      — WebRTC offer/answer choices (codecs, ZRTP mode, DTMF
//              transport, in-call recording toggle)
//   device   — hardware-behaviour switches (proximity sensor, etc.)
//   location — live-location feature knobs
//
// Setters use dotted paths: setAccountSetting('rtp.dtmfMode', 'info').
// Future sections (e.g. network, debug) plug in here
// without touching the dispatch logic.
const ACCOUNT_SETTINGS_DEFAULTS = Object.freeze({
    // ---- Real-time media (audio + video + recording + DTMF + zRTP) ----
    rtp: Object.freeze({
        // Codec preferences depend on this device's hardware encoder /
        // decoder availability. Two devices logged into the same SIP
        // account legitimately want different choices.
        preferredVideoCodec: PREFERRED_VIDEO_CODEC,   // 'VP9'
        preferredAudioCodec: PREFERRED_AUDIO_CODEC,   // 'opus'
        // Conference video codec — the user's preferred codec for
        // outgoing conferences. USER WINS: this preference always
        // takes effect when set. The server's per-domain
        // sylk-config.json may publish a value (mirrored in
        // state.conferenceVideoCodec — same key name at the top
        // level of state, different namespace) as a *recommended*
        // fallback used only when the user hasn't expressed a
        // preference. See _applyConferenceVideoCodec.
        // 'VP8' is the safe default — Janus has supported it across
        // every release.
        conferenceVideoCodec: 'VP8',
        // ZRTP key-agreement mode for outgoing calls.
        encryptionMode: 'zrtp_optional',
        // DTMF transmission. 'info' = SIP INFO (Janus-side), 'rfc4733'
        // = out-of-band telephone-event RTP. 'inband' is no longer
        // offered.
        dtmfMode: 'info',
        // Whether the in-call record control is shown on audio calls.
        enableAudioRecording: false,
    }),
    // ---- Device hardware behaviour --------------------------------------
    device: Object.freeze({
        // Proximity sensor: when true, holding the phone to the ear
        // during an audio call routes audio to the earpiece and
        // blanks the screen. ON by default — matches native phone
        // behaviour.
        proximityEnabled: true,
        // Developer-mode toggle. Surfaces verbose logging, dev-only
        // panels, etc. Migrated out of AsyncStorage 'devMode'.
        devMode: false,
        // Whether to play a sound on chat events. Lives here (device)
        // rather than privacy because it's a per-device speaker
        // behaviour, not a privacy / call-acceptance rule. Migrated
        // out of accounts.chat_sounds.
        chatSounds: true,
        // Last picked camera / mic devices, kept as compact descriptor
        // objects { deviceId, label } so getLocalMedia can match by
        // either id (preferred) or label (fallback when ids rotate).
        // Migrated out of AsyncStorage 'devices' which used the same
        // shape under .camera / .mic.
        cameraDevice: null,
        micDevice: null,
        // Active video quality profile id. One of VIDEO_PROFILE_IDS
        // ('480p' / '720p' / '1080p'); resolved to a concrete
        // {width, height, frameRate, maxBitrateKbps} via
        // VIDEO_PROFILES[id]. Drives getLocalMedia's camera-side
        // constraints and the libwebrtc-side encoder caps applied
        // by CallZrtp.setVideoEncoderTarget /
        // setVideoMaxBitrateKbps. Settable from Preferences →
        // Video; changing it re-applies to the active call via
        // reapplyVideoEncoderParams so the bump takes effect mid-
        // call without a hang-up + redial.
        videoProfile: VIDEO_PROFILE_DEFAULT_ID,
        // Active visual theme. 'system' = follow the OS Appearance
        // setting (default; preserves the historical behaviour);
        // 'day' = force the light, WhatsApp-styled look; 'night' =
        // force the dark Sylk look. Read by NavigationBar / ChatBubble
        // via DarkModeManager.getTheme(); the setter (Preferences →
        // Theme) writes here AND calls DarkModeManager.setMode() so
        // the in-memory singleton stays in sync with the persisted
        // value. Per-device (lives in the device section) because
        // theme is a screen / form-factor opinion — two phones logged
        // into the same SIP account can legitimately want different
        // themes (one in a bright office, one always at night).
        themeMode: 'system',
    }),
    // ---- Privacy / call-acceptance & messaging behaviour ---------------
    // Moved out of the dedicated SQL columns
    //   accounts.dnd
    //   accounts.reject_anonymous
    //   accounts.reject_non_contacts
    //   accounts.read_receipts
    // into this JSON section. The native push handlers (iOS
    // AppDelegate.m and Android MyFirebaseMessagingService.java) parse
    // the accounts.settings blob to read dnd / rejectAnonymous /
    // rejectNonContacts on push arrival — no more per-column SQL
    // schema coupling between JS and native. The old columns remain
    // in the schema as dead weight (safer rollback) but are no
    // longer written; a future migration can drop them.
    //
    // (chat_sounds moved to device.chatSounds — it's a per-device
    // speaker behaviour, not a privacy / call-acceptance rule.)
    //
    // readReceipts default ON — accounts before the read-receipts
    //   feature got `null` in the old column, which loadAccount used
    //   to coerce to true; preserve that semantic here.
    privacy: Object.freeze({
        dnd: false,
        rejectAnonymous: false,
        rejectNonContacts: false,
        readReceipts: true,
    }),
    // (NOTE: the server-journal sync cursor is NOT in this map. It's
    // runtime state — accounts.last_sync_id and
    // accounts.last_sync_timestamp are its source of truth. It only
    // appears in the LOAD/SAVE dump as a virtual `[journal]` section
    // so you can see the cursor alongside the settings — see
    // formatAccountSettings + the call site that injects it.)
    // ---- Per-account app behaviour --------------------------------------
    account: Object.freeze({
        // Global auto-answer toggle. When true, every incoming call is
        // auto-accepted. Per-contact overrides live on the contact
        // row (localProperties.autoanswer) and are unaffected. Migrated
        // out of AsyncStorage 'autoAnswerMode'.
        autoAnswerMode: false,
        // User's own mobile phone number, used as Caller ID when
        // calling PSTN destinations. Captured on the first PSTN dial
        // (callKeepStartCall asks for READ_PHONE_NUMBERS, reads the
        // SIM number via react-native-device-info's getPhoneNumber(),
        // and persists it here through setAccountSetting). Empty
        // string = "not yet captured / user declined / no SIM" — in
        // which case we fall back to the device-info value held in
        // state.myPhoneNumber. Per-account because the same physical
        // device can be used by two accounts with different billing
        // numbers; per-account storage lets each pick its own.
        myPhoneNumber: '',
    }),
    // ---- Live-location feature knobs ------------------------------------
    location: Object.freeze({
        // Heartbeat cadence (seconds). NavigationBar multiplies ×1000
        // before handing to setInterval.
        tickIntervalSec: 60,
        // Meet-up auto-end threshold — both participants within this
        // radius for the dwell window get a "you've met"
        // notification and the share auto-ends.
        proximityMeters: 20,
        // Last-used privacy radius for meeting-handshake shares,
        // 0 = "Off" (no privacy radius).
        privacyRadiusMeters: 0,
    }),
    // ---- Conference settings published by the server --------------------
    // This section is NOT a user preference — it mirrors values pulled
    // from the per-domain server configuration (sylk-config.json's
    // `conference` block) into the accounts.settings JSON so the
    // NATIVE push-receipt code can read them via sqlite3 without going
    // through any JS bridge call at receipt time.
    //
    // sipBridge in particular is consulted by
    // AppDelegate.shouldDisplayMessageFromPayload (iOS) and
    // MyFirebaseMessagingService (Android) to drop the duplicate
    // "incoming_session" push that the conference focus SIP-dials in
    // parallel with the real "incoming_conference_request" push — the
    // dedupe is what stops the second "Tap to join" CallKit ring from
    // appearing alongside the conference invite. Native reads it from
    // the same accounts.settings JSON it already opens for privacy
    // flags (privacy.dnd, privacy.rejectAnonymous,
    // privacy.rejectNonContacts) — see AppDelegate.m line 380-422 for
    // the existing read pattern. SQL is the single source of truth;
    // no NSUserDefaults / SharedPreferences mirror, no AsyncStorage
    // cache.
    //
    // Written by applySipBridgeDomain whenever initConfiguration
    // ingests fresh server config. Per-account because each account
    // is bound to its own server domain (accounts.server) and
    // different deployments may publish different sipBridge hosts.
    conference: Object.freeze({
        sipBridge: null,
    }),
    // ---- Legal-disclaimer acknowledgement flags -------------------------
    // Migrated out of AsyncStorage keys
    //   locationDisclosureAcknowledged.v2.<accountId>
    //   callRecordingDisclosureAcknowledged.v1.<accountId>
    // The old per-account-keyed AsyncStorage flags are no longer read
    // (no carry-over by design — first launch after upgrade re-prompts).
    // The disclosure modules (locationDisclosure.js,
    // callRecordingDisclosure.js) now route reads/writes here through
    // accountSettingsAccess.js so existing call sites (AudioCallBox,
    // PreferencesModal, NavigationBar, app.js) keep working unchanged.
    disclaimers: Object.freeze({
        // Google Play "before-the-fact in-app location disclosure"
        // policy acknowledgement. Required by Play policy before any
        // GPS read.
        locationPolicy: false,
        // "Call recording can have legal consequences" acknowledgement.
        // Gates the Auto-record toggle in Preferences and the in-call
        // record button in AudioCallBox.
        callRecording: false,
        // Whether we've already prompted the user once for the
        // Android Do-Not-Disturb permission (one-shot). Migrated out
        // of AsyncStorage 'askedDndPermission'.
        askedDndPermission: false,
    }),
});

function parseAccountSettingsBlob(raw) {
    if (!raw) return {};
    try {
        const v = JSON.parse(raw);
        return (v && typeof v === 'object') ? v : {};
    } catch (e) {
        console.log('parseAccountSettingsBlob failed:', e);
        return {};
    }
}

// Layer ACCOUNT_SETTINGS_DEFAULTS underneath whatever was loaded from
// disk, section by section. Unknown sections in the stored blob are
// preserved (so a downgrade from a future build that knows about a
// section we don't won't silently drop user choices).
function applyAccountSettingDefaults(props) {
    const stored = props || {};
    const out = {};
    for (const section of Object.keys(ACCOUNT_SETTINGS_DEFAULTS)) {
        out[section] = {
            ...ACCOUNT_SETTINGS_DEFAULTS[section],
            ...(stored[section] || {}),
        };
    }
    // Carry over any sections the running build doesn't know about so
    // downgrading from a future schema doesn't silently lose data.
    for (const section of Object.keys(stored)) {
        if (!(section in out)) out[section] = stored[section];
    }
    return out;
}

// Pretty-print the sectioned account-settings dict for the console /
// log viewer. One section per group, key=value aligned, no JSON
// braces or quotes — the goal is "I can scan this on the device log
// and see every preference at a glance".
//
// `extras` is an optional second object whose top-level keys are
// merged in as additional sections after the settings ones, so
// callers can append "virtual" sections (e.g. `journal` runtime
// state) that aren't actually part of accounts.settings.
function formatAccountSettings(props, extras) {
    const obj = props || {};
    const merged = { ...obj, ...(extras || {}) };
    const sections = Object.keys(merged);
    if (sections.length === 0) return '\n  (empty)';
    const lines = [];
    for (const section of sections) {
        const sec = (merged[section] && typeof merged[section] === 'object') ? merged[section] : {};
        lines.push('  [' + section + ']');
        const keys = Object.keys(sec);
        if (keys.length === 0) {
            lines.push('    (empty)');
            continue;
        }
        const width = Math.max(...keys.map(k => k.length));
        for (const k of keys) {
            const v = sec[k];
            let shown;
            if (v === null || v === undefined) {
                shown = '(default)';
            } else if (typeof v === 'object') {
                // Compact JSON for object values (e.g. cameraDevice /
                // micDevice device descriptors). Keeps the dump line
                // scannable without wrapping; full structure is still
                // visible.
                try { shown = JSON.stringify(v); }
                catch (e) { shown = '[object]'; }
            } else {
                shown = String(v);
            }
            lines.push('    ' + k.padEnd(width) + '  ' + shown);
        }
    }
    return '\n' + lines.join('\n');
}
if (sylkrtc.utils && sylkrtc.utils.setPreferredVideoCodec) {
    sylkrtc.utils.setPreferredVideoCodec(PREFERRED_VIDEO_CODEC);
    const fmt = (v, suffix='') => v === null ? 'default' : v + suffix;
    console.log('[SylkE2EE-Build]', SYLK_E2EE_BUILD,
                '| preferred video codec =', PREFERRED_VIDEO_CODEC,
                '| video', fmt(VIDEO_PROFILE.width) + 'x' + fmt(VIDEO_PROFILE.height),
                '@', fmt(VIDEO_PROFILE.frameRate, 'fps'),
                'cap', fmt(VIDEO_PROFILE.maxBitrateKbps, 'kbps'));
}
// Audio codec setter is exposed by sylkrtc utils once the audio-codec
// patch is in place. Guarded the same way as the video setter so an
// older sylkrtc build (without the patch) still boots cleanly — codec
// preference simply has no effect in that case and libwebrtc's
// default opus offer is what goes out.
if (sylkrtc.utils && sylkrtc.utils.setPreferredAudioCodec) {
    sylkrtc.utils.setPreferredAudioCodec(PREFERRED_AUDIO_CODEC);
    console.log('[SylkE2EE-Build] preferred audio codec =', PREFERRED_AUDIO_CODEC);
}
// Mirror the codec choice into the in-app log file UNCONDITIONALLY —
// outside the sylkrtc.utils.setPreferredVideoCodec guard above, so
// the user always sees what the build is using even on sylkrtc
// versions that don't expose the setter. Inline require() (rather
// than the module-level `import utils` which doesn't appear until
// further down the file) so this runs at module-eval time without
// a TDZ-style undefined reference.
require('./utils').timestampedLog('[video] preferred video codec at start =',
    PREFERRED_VIDEO_CODEC || 'default');
require('./utils').timestampedLog('[audio] preferred audio codec at start =',
    PREFERRED_AUDIO_CODEC || 'default');
setVideoMaxBitrateKbps(VIDEO_PROFILE.maxBitrateKbps);
// Encoder-side downscale + framerate cap. Camera-side getUserMedia
// constraints are only a hint on Android (react-native-webrtc maps
// them to Camera2 preview-size selection, which silently picks a
// larger mode when no exact match exists — e.g. Motorola razrs handing
// us 1088x1088 / 30 fps despite our 640x480 / 24 fps ask). These
// encoder knobs run AFTER the camera inside libwebrtc, so they
// guarantee the wire-side resolution and framerate match the profile.
setVideoEncoderTarget(VIDEO_PROFILE.width, VIDEO_PROFILE.height, VIDEO_PROFILE.frameRate);

// Verify the native sylk_e2ee binary on both Android and iOS reports the
// same SYLK_E2EE_BUILD string the JS expects. Mismatch means one of:
//   - patch-package didn't run (rare with the postinstall hook)
//   - rebuild used a stale .cxx / Pods cache (most common cause)
//   - the running APK / IPA is older than the JS bundle Metro is serving
// Fire-and-forget — we don't want to hold up app startup.
(async () => {
    try {
        const { NativeModules } = await import('react-native');
        const mod = NativeModules && NativeModules.WebRTCModule;
        if (!mod || typeof mod.getSylkE2EEBuild !== 'function') {
            console.log('[SylkE2EE-Build] native getSylkE2EEBuild() not exposed — '
                      + 'old react-native-webrtc binary; expected build', SYLK_E2EE_BUILD);
            return;
        }
        const native = await mod.getSylkE2EEBuild();
        if (native === SYLK_E2EE_BUILD) {
            console.log('[SylkE2EE-Build] native matches JS:', native);
        } else {
            console.warn('[SylkE2EE-Build] *** MISMATCH ***\n'
                       + '  JS expects:    ' + SYLK_E2EE_BUILD + '\n'
                       + '  native loaded: ' + native + '\n'
                       + '  → run ./rebuild-webrtc.sh --reinstall to fix');
        }
        // DTMF bridge probe: are senderInsertDtmf / senderCanInsertDtmf
        // present on the rebuilt native module? If both are functions we
        // are running the new build; if either is missing the rebuild
        // didn't pick up the patches/edits and DTMF will silently
        // no-op in RTCDTMFSender.insertDTMF (the JS-side guard short-
        // circuits when the bridge method doesn't exist).
        // Probe the RFC 4733 bridge. SIP INFO is the default DTMF
        // mode now (PreferencesModal → DTMF → "SIP INFO") and goes
        // entirely over the websocket / sylkserver / Janus path
        // with no native bridge involvement, so the only native
        // side worth probing here is the RFC 4733 fallback path.
        // (playInbandDtmf is still wired in WebRTCModule.java as a
        // no-op for libwebrtc 124, kept for a potential future
        // M132+ upgrade — not user-facing, not worth a startup
        // warning.)
        const insertOk = typeof mod.senderInsertDtmf === 'function';
        const canOk = typeof mod.senderCanInsertDtmf === 'function';
        if (insertOk && canOk) {
            console.log('[DTMF-Build] native bridge OK — '
                + 'senderInsertDtmf + senderCanInsertDtmf exposed');
        } else {
            console.warn('[DTMF-Build] *** RFC 4733 bridge partial / missing ***\n'
                       + '  senderInsertDtmf:    ' + (insertOk ? 'present' : 'MISSING') + '\n'
                       + '  senderCanInsertDtmf: ' + (canOk ? 'present' : 'MISSING') + '\n'
                       + '  → rebuild react-native-webrtc. '
                       + 'SIP INFO mode (the default) still works without this — '
                       + 'only the rfc4733 fallback is affected.');
        }
    } catch (e) {
        console.log('[SylkE2EE-Build] native build probe threw:', (e && e.message) || e);
    }
})();
