        // _initialState) because the logout path resets state back to
        // _initialState — a live meeting-request modal is UI-only and
        // should not survive a logout anyway.
        this.state.meetingRequestModal = {
            show: false,
            fromUri: null,
            requestId: null,
            expiresAt: null,
        };

        // "Please share your current location" prompt — symmetric to
        // meetingRequestModal but a one-shot Yes/No: on Yes we ship a
        // single location bubble back via NavBar.shareLocationOnce.
        this.state.locationRequestModal = {
            show: false,
            fromUri: null,
            requestId: null,
            expiresAt: null,
        };
        // Ids of incoming location requests we've already presented
        // (modal shown or expired). Memory-only — restoring across
        // restarts isn't worth the AsyncStorage round-trip for a
        // throwaway prompt.
        this.handledLocationRequestIds = new Set();
        // Distinct from `handledLocationRequestIds`: this set is
        // populated ONLY when a sibling device on the same account
        // answers a location request. The pre-modal 2 s delay
        // consults this set to skip presenting the modal if a
        // sibling already answered while we were waiting. We can't
        // reuse handledLocationRequestIds for that purpose because
        // _presentLocationRequestForUri stamps it BEFORE scheduling
        // the modal-presenting setTimeout — checking handled inside
        // the setTimeout would always be true and the modal would
        // never open.
        this.siblingAnsweredLocationRequestIds = new Set();
        // Per-peer pending request, keyed by sender uri.
        this.pendingLocationRequests = {};

        // ===== Conference-request handshake (in-call "Escalate to
        // conference" via the avatar "+" panel) =====
        //
        // conferenceRequestModal mirrors locationRequestModal in shape:
        // the receiver-side popup reads from it. `room` is the
        // conference URI the requester proposed — the accept echo MUST
        // carry the same value so both sides converge on the same
        // room. `expiresAt` is the request's deadline in ms (60 s
        // window by convention).
        this.state.conferenceRequestModal = {
            show: false,
            fromUri: null,
            requestId: null,
            expiresAt: null,
            room: null,
        };
        // Ids of incoming conference requests we've already presented
        // OR replied to. Prevents re-prompting on metadata replay /
        // socket reconnect.
        this.handledConferenceRequestIds = new Set();
        // Outgoing requests we've sent and are waiting on. Keyed by
        // peer uri so we can match the accept echo from `author`.
        // Value: { requestId, room, expiresAt, peerUri, callId }.
        this.pendingOutgoingConferenceRequests = {};
        this._conferenceRequestModalDismissTimerId = null;

        // this.myParticipants — REMOVED. The per-room collected
        // participant list was only ever read by a commented-out
        // block in the /call render path; no consumer remains.
        this.outgoingJournalEntries = {};
        
        this.outgoingNotifications = {};

        this._historyConferenceParticipants = new Map(); // for saving to local history

        this._terminatedCalls = new Map();

        // Incoming calls that lost their [wss] before the user could answer.
        // Keyed by callUUID, value is {from, displayName, mediaType, addedAt, timer}.
        // While a UUID is in this map it is NOT in _terminatedCalls, so when the
        // [wss] reconnects and the server redelivers the same INCOMING offer it
        // is allowed through autoRejectIncomingCall instead of being silently
        // dropped as "already terminated". The OS-level CallKeep / heads-up
        // notification stays visible during the gap because it's driven by FCM
        // push, independent of our [wss] state. See connectionStateChanged
        // ('disconnected') and _holdIncomingCallForRevival.
        this._revivableIncomingCalls = new Map();

